const body = $input.first().json;
const actions = body.actions || [];

// Validate actions
const validTypes = ['goto', 'click', 'fill', 'screenshot', 'wait', 'extract', 'scroll', 'select', 'upload'];
const validActions = actions.filter(a => validTypes.includes(a.type));

return {
  url: body.url,
  actions: validActions,
  userAgent: body.userAgent || 'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36',
  taskId: Date.now().toString()
};

parameters.command:
=node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch();
  const page = await browser.newPage();
  const actions = $node['Parse Actions'].json.actions;
  const results = [];
  await page.goto('{{$node['Parse Actions'].json.url}}');
  for (const action of actions) {
    switch(action.type) {
      case 'wait': await page.waitForSelector(action.selector, {timeout: 10000}); break;
      case 'click': await page.click(action.selector); break;
      case 'fill': await page.fill(action.selector, action.text || ''); break;
      case 'screenshot': 
        await page.screenshot({path: action.path || '/tmp/screenshot.png', fullPage: action.fullPage || false}); 
        break;
      case 'scroll': await page.evaluate((y) => window.scrollBy(0, y), action.y || 500); break;
      case 'extract': 
        const els = await page.$$(action.selector);
        const data = await Promise.all(els.map(el => action.attr ? el.getAttribute(action.attr) : el.textContent()));
        results.push({type: action.type, selector: action.selector, data});
        break;
    }
  }
  await browser.close();
  console.log(JSON.stringify({success: true, results}));
})();"

