const results = $input.all();
const parsed = $node['Parse Actions'].json;

const extracted = results
  .filter(r => r.json && r.json.type === 'extract')
  .map(r => r.json.data)
  .flat();

return {
  taskId: parsed.taskId,
  url: parsed.url,
  actionsCount: parsed.actions.length,
  extractedData: extracted,
  results,
  timestamp: new Date().toISOString()
};

